  ('dietitian-moex-07904', 'dietitian', 'dietitian-moex-100-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品GMP之規定，可用總落菌數為指標，做為餐飲作業場所清潔度的判斷。下列有關清潔度測定方 法的敘述，何者錯誤？', '["使用含標準洋菜培養基的直徑9公分培養皿", "培養皿在取樣點開蓋平放15分鐘後上蓋", "培養基於35℃培養48±2小時", "計數2-3皿而得平均落菌量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "95b6858b327e", "answer_pdf_sha1": "24e96fb9caff", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
