  ('dietitian-moex-07908', 'dietitian', 'dietitian-moex-100-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '使用氣隔（air gap）防止飲用水受到回流之污染，依行政院環境保護署規定，給水管（水龍頭）和水面之 垂直距離至少為：', '["給水管直徑之2倍，但不得少於1.3公分（1/2英吋）", "給水管直徑之2倍，但不得少於5公分（2英吋）", "給水管直徑之3倍，但不得少於5公分（2英吋）", "給水管直徑之4倍，但不得少於7.6公分（3英吋）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "95b6858b327e", "answer_pdf_sha1": "24e96fb9caff", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
